const fs = require('fs');
const path = require('path');
const childProcess = require('child_process');

// Set environment variables
process.env.NODE_ENV = 'production';

// Define functions for each task
function installDependencies() {
  return new Promise((resolve, reject) => {
    const npmInstallCommand = `npm install --only=prod`;
    childProcess.exec(npmInstallCommand, (error) => {
      if (error) {
        console.error('Error installing dependencies:', error);
        reject(error);
      } else {
        resolve();
      }
    });
  });
}

function runTests() {
  return new Promise((resolve, reject) => {
    const npmTestCommand = `npm test`;
    childProcess.exec(npmTestCommand, (error) => {
      if (error) {
        console.error('Error running tests:', error);
        reject(error);
      } else {
        resolve();
      }
    });
  });
}

function buildApplication() {
  return new Promise((resolve, reject) => {
    const npmBuildCommand = `npm run build`;
    childProcess.exec(npmBuildCommand, (error) => {
      if (error) {
        console.error('Error building application:', error);
        reject(error);
      } else {
        resolve();
      }
    });
  });
}

function deployToProduction() {
  return new Promise((resolve, reject) => {
    const deploymentSecret = fs.readFileSync(path.join(__dirname, 'deployment-secret'), 'utf8');
    const deploymentCommand = `npm run deploy --secret=${deploymentSecret}`;
    childProcess.exec(deploymentCommand, (error) => {
      if (error) {
        console.error('Error deploying to production:', error);
        reject(error);
      } else {
        resolve();
      }
    });
  });
}

// Main pipeline function
async function pipeline() {
  try {
    await installDependencies();
    await runTests();
    await buildApplication();
    await deployToProduction();
    console.log('Deployment successful!');
  } catch (error) {
    console.error('Error in deployment pipeline:', error);
  }
}

pipeline();